SELECT COUNT(calibration_id) AS calibration_count
FROM calibrations
WHERE technician_id = 0;

SELECT calibration_status, notes
FROM calibrations
WHERE calibration_status = 'fail';

SELECT device_name
FROM devices
ORDER BY device_name;

SELECT scheme_id, scheme_name, compression_ratio
FROM compression_schemes
WHERE compression_ratio = (
    SELECT MAX(compression_ratio) FROM compression_schemes
);

SELECT calibration_status, COUNT(*) AS calibration_count
FROM calibrations
GROUP BY calibration_status;

SELECT DISTINCT t.technician_name
FROM technicians t
JOIN calibrations c ON t.technician_id = c.technician_id;

SELECT configuration_description
FROM device_history
WHERE device_id = 0 AND configuration_date BETWEEN '2023-01-01' AND '2023-01-31';
